"use client";

// `lucide-animated` has no `SendIcon` (or `SquareIcon` runtime export
// — typing-only). Use static lucide-react for both glyphs; the
// composer's morph button also uses the same `Send` icon, so the
// visitor sees a consistent send affordance across the widget.
import { Send, Square } from "lucide-react";
import { motion } from "motion/react";
import { useTranslations } from "next-intl";
import { type ComponentType, useEffect, useRef, useState } from "react";
import WaveSurfer from "wavesurfer.js";
import RecordPlugin from "wavesurfer.js/dist/plugins/record.esm.js";
import { PauseIcon, PlayIcon, XIcon } from "@/components/widget/icons/animated";
import { useIconHover } from "@/lib/use-icon-hover";
import { cn } from "@/lib/utils";
import { blobToBase64, formatDuration, pickMime } from "./helpers";

export interface VoiceRecording {
  /** MIME of the captured blob (`audio/webm;codecs=opus` on Chrome,
   *  `audio/mp4` on Safari). */
  mimetype: string;
  /** Raw base64 payload — no `data:…;base64,` prefix; ready for the
   *  BE's `uploadVisitorMedia` mutation. */
  base64: string;
  /** Decoded byte length — caller compares against the 10 MB cap. */
  size: number;
  /** `voice-<ts>.<ext>` — picked from the recorder's mimetype. */
  filename: string;
}

interface VoiceRecorderBarProps {
  /** Visitor tapped Send in preview — ship the blob + close. */
  onComplete: (rec: VoiceRecording) => void;
  /** Visitor tapped Cancel at any phase — close, no upload. */
  onCancel: () => void;
  /** Mic permission denied / no MediaRecorder support / etc. */
  onError: (kind: "denied" | "unsupported" | "failed") => void;
}

/**
 * Replaces the chat composer while the visitor is recording a voice
 * note. Two phases — `recording` → `preview` — and a hand-rolled
 * `MediaRecorder` for capture so we don't depend on the
 * `wavesurfer.js` Record plugin's internal `record-end` plumbing
 * (which has subtle event-unsubscribe races when its `stopMic` runs;
 * the symptom was the Stop button silently doing nothing in some
 * browsers). The plugin is still in play — but only for the live
 * mic-stream visualisation; the recorded blob comes from our own
 * recorder.
 *
 * **Lifecycle**:
 *   - mount  → ask for mic permission, hand the stream to the
 *              plugin for the live waveform AND start our own
 *              `MediaRecorder` collecting chunks.
 *   - stop   → stop OUR recorder; its `onstop` builds the blob,
 *              stops the plugin's live render, loads the blob into
 *              wavesurfer for playback, and flips phase to `preview`.
 *   - cancel → bail (no upload).
 *   - send   → hand the cached blob to `onComplete`.
 *
 * **Brand fidelity**: wavesurfer canvas can't resolve CSS variables;
 * we read `--wx-primary` / `--wx-fg-muted` from the document root on
 * mount and feed real hex values to the instance so the waveform
 * matches the operator's accent in both themes.
 */
export function VoiceRecorderBar({ onComplete, onCancel, onError }: VoiceRecorderBarProps) {
  const t = useTranslations("messages");
  const containerRef = useRef<HTMLDivElement | null>(null);
  const wavesurferRef = useRef<WaveSurfer | null>(null);
  // Narrow shape of the plugin API surface we actually call. We
  // don't subscribe to its events — we just use it for mic + waveform.
  const recordPluginRef = useRef<{
    startMic: () => Promise<MediaStream>;
    stopMic: () => void;
  } | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const tickIntervalRef = useRef<number | null>(null);

  const [phase, setPhase] = useState<"recording" | "preview">("recording");
  const [elapsedSec, setElapsedSec] = useState(0);
  const [previewPlaying, setPreviewPlaying] = useState(false);
  // Encoded blob — held so Send fires onComplete with no second
  // base64 round-trip.
  const recordedRef = useRef<VoiceRecording | null>(null);
  // True only when the visitor explicitly cancelled (X button).
  // Different from the per-effect "strict-mode cancelled" flag —
  // that one lives inside the effect closure so the React 18
  // dev-strict double-mount doesn't wedge state.
  const userCancelledRef = useRef(false);

  // Mount-only — the recorder instance is single-shot per session, so
  // `onError` (and the other captured callbacks) are deliberately NOT
  // deps: re-running this would re-acquire the mic on every parent
  // render that passes a fresh callback identity.
  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional mount-only mic-acquisition effect — see note above
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    if (typeof window === "undefined" || !window.MediaRecorder) {
      onError("unsupported");
      return;
    }

    // `effectCancelled` is captured in this effect's closure ONLY —
    // each strict-mode re-mount gets its own. The old ref-based flag
    // was shared across both runs: the first cleanup set it to true,
    // the second effect's async `startMic().then(...)` then bailed
    // because the ref was still true. Result on dev: recorder never
    // even started. Local-scoping the flag fixes it.
    let effectCancelled = false;
    userCancelledRef.current = false;

    // Read the theme tokens off the CONTAINER, not
    // `document.documentElement` — in the React-component embed the
    // `--wx-*` vars live on the Shadow DOM host, never on the host
    // page's `<html>`, so `documentElement` would resolve to empty and
    // the waveform would always fall back to the hardcoded colours.
    // The container inherits the vars in every embed mode.
    const styles = getComputedStyle(container);
    const primary = styles.getPropertyValue("--wx-primary").trim() || "#5b6cff";
    const muted = styles.getPropertyValue("--wx-fg-muted").trim() || "#6b7280";

    const ws = WaveSurfer.create({
      container,
      waveColor: muted,
      progressColor: primary,
      cursorColor: primary,
      cursorWidth: 2,
      height: 32,
      barWidth: 2,
      barGap: 2,
      barRadius: 2,
      interact: true,
      // `continuousWaveform` makes wavesurfer's internal scroll element
      // wider than the bar — it would otherwise paint its own
      // horizontal scrollbar under the waveform. Visitors never scroll
      // a live recording / short voice note, so hide it.
      hideScrollbar: true,
    });
    wavesurferRef.current = ws;

    ws.on("play", () => setPreviewPlaying(true));
    ws.on("pause", () => setPreviewPlaying(false));
    ws.on("finish", () => setPreviewPlaying(false));

    const plugin = ws.registerPlugin(
      RecordPlugin.create({
        continuousWaveform: true,
        continuousWaveformDuration: 60,
        // `renderRecordedAudio: false` — we drive the playback load
        // ourselves once recording stops, so the plugin shouldn't
        // try to load its own (empty) buffer.
        renderRecordedAudio: false,
      }),
    ) as unknown as NonNullable<typeof recordPluginRef.current>;
    recordPluginRef.current = plugin;

    // Local mirrors captured in this effect's closure — used by
    // cleanup so we tear down THIS effect's resources, not whatever
    // the (newer) component instance has set into the shared refs.
    let localTickInterval: number | null = null;
    let localRecorder: MediaRecorder | null = null;

    /**
     * Two-step bring-up so the plugin's live waveform AND our
     * MediaRecorder both feed off the same mic stream:
     *
     *   1. `plugin.startMic()` does `getUserMedia` + sets up an
     *      AudioContext → AnalyserNode → canvas-drawing interval.
     *   2. We attach `MediaRecorder` to that stream for capture.
     *
     * If `getUserMedia` rejects, surface as `denied`; everything
     * else lands in `failed`.
     */
    plugin
      .startMic()
      .then((stream) => {
        if (effectCancelled || userCancelledRef.current) {
          // Strict-mode tear-down: cleanup already ran (it called
          // plugin.stopMic() while `this.stream` was still null
          // because getUserMedia hadn't resolved yet). Now that
          // getUserMedia HAS resolved, the plugin set its `stream`
          // to this freshly-acquired one — nobody will release it
          // unless we do. Stop the tracks here so the OS mic
          // indicator clears.
          try {
            stream.getTracks().forEach((track) => {
              track.stop();
            });
          } catch {}
          try {
            plugin.stopMic();
          } catch {}
          return;
        }
        const mime = pickMime();
        const recorder = mime
          ? new MediaRecorder(stream, { mimeType: mime })
          : new MediaRecorder(stream);
        mediaRecorderRef.current = recorder;
        localRecorder = recorder;
        chunksRef.current = [];
        recorder.addEventListener("dataavailable", (e) => {
          if (e.data && e.data.size > 0) chunksRef.current.push(e.data);
        });
        recorder.addEventListener("stop", () => {
          // strict-mode tear-down OR user cancel → discard the take.
          if (effectCancelled || userCancelledRef.current) return;
          // Release the mic + live-waveform render IMMEDIATELY (not
          // after base64 encoding). FileReader can take hundreds of
          // ms on long recordings — without this the browser keeps
          // the "tab is using microphone" indicator on for that
          // whole window after the visitor already tapped Stop.
          try {
            plugin.stopMic();
          } catch {}
          if (localTickInterval !== null) {
            clearInterval(localTickInterval);
            localTickInterval = null;
            tickIntervalRef.current = null;
          }
          const finalMime = recorder.mimeType || mime || "audio/webm";
          const blob = new Blob(chunksRef.current, { type: finalMime });
          blobToBase64(blob)
            .then((base64) => {
              if (effectCancelled || userCancelledRef.current) return;
              const ext = finalMime.includes("mp4") ? "mp4" : "webm";
              // `recorder.mimeType` carries the codec param
              // (`audio/webm;codecs=opus`). The upload allowlist (client +
              // the BE's `WebUploadService.ALLOWED_MIMES`) matches the BARE
              // type `audio/webm`, so the codec suffix 415s. Strip it for the
              // upload — the blob above keeps the full type for local
              // playback, where the codec still gets inferred.
              const uploadMime = finalMime.split(";")[0].trim();
              recordedRef.current = {
                base64,
                mimetype: uploadMime,
                size: blob.size,
                filename: `voice-${Date.now()}.${ext}`,
              };
              // Load the playable blob THEN reset cursor +
              // re-enable seeking:
              //   1. The plugin's `renderMicStream` force-sets
              //      `interact: false` and (because we set
              //      `renderRecordedAudio: false`) never restores
              //      it — re-flip here so the visitor can scrub.
              //   2. During recording the plugin called
              //      `setTime(duration / 1000)` on every tick, so
              //      after stop the cursor sits at the end. Reset
              //      to 0 so playback starts at the beginning.
              //
              // `loadBlob(blob)` — NOT `load(objectURL)`: wavesurfer's
              // `load()` does a `fetch()` of the URL, and a host page
              // with a strict `connect-src` CSP (no `blob:`) blocks
              // fetching `blob:` URLs — the preview would hang on a
              // forever spinner. `loadBlob` decodes the in-memory Blob
              // directly, no network request, no CSP surface.
              ws.loadBlob(blob)
                .then(() => {
                  if (effectCancelled || userCancelledRef.current) return;
                  try {
                    ws.setOptions({ interact: true });
                  } catch {}
                  try {
                    ws.setTime(0);
                  } catch {}
                })
                .catch(() => {});
              setPhase("preview");
            })
            .catch(() => onError("failed"));
        });
        recorder.start();

        // Drive the duration counter from our own tick — independent
        // of the plugin so the counter survives any plugin oddity.
        // Only setElapsedSec when the displayed second changes so we
        // don't trigger 10 renders/sec.
        const startedAt = performance.now();
        localTickInterval = window.setInterval(() => {
          const ms = performance.now() - startedAt;
          const sec = Math.floor(ms / 1000);
          setElapsedSec((prev) => (prev === sec ? prev : sec));
        }, 250);
        tickIntervalRef.current = localTickInterval;
      })
      .catch((err: Error) => {
        if (effectCancelled) return;
        const msg = err?.message ?? "";
        onError(msg.includes("Permission") || msg.includes("denied") ? "denied" : "failed");
      });

    return () => {
      effectCancelled = true;
      if (localTickInterval !== null) {
        clearInterval(localTickInterval);
      }
      try {
        if (localRecorder?.state === "recording") {
          localRecorder.stop();
        }
      } catch {}
      try {
        plugin.stopMic();
      } catch {}
      ws.destroy();
      // Only null shared refs if this effect's instance is still the
      // one parked there — protects against the strict-mode race
      // where the second effect's setup races past this cleanup.
      if (wavesurferRef.current === ws) wavesurferRef.current = null;
      if (recordPluginRef.current === plugin) recordPluginRef.current = null;
      if (mediaRecorderRef.current === localRecorder) {
        mediaRecorderRef.current = null;
      }
    };
  }, []);

  const handleCancel = () => {
    userCancelledRef.current = true;
    try {
      if (mediaRecorderRef.current?.state === "recording") {
        mediaRecorderRef.current.stop();
      }
    } catch {}
    try {
      recordPluginRef.current?.stopMic();
    } catch {}
    try {
      wavesurferRef.current?.pause();
    } catch {}
    onCancel();
  };

  const handleStop = () => {
    // Stops OUR MediaRecorder. Its `stop` listener does the rest —
    // builds the blob, swaps wavesurfer to playback mode, flips
    // phase to `preview`.
    try {
      if (mediaRecorderRef.current?.state === "recording") {
        mediaRecorderRef.current.stop();
      }
    } catch {}
  };

  const handlePreviewToggle = () => {
    const ws = wavesurferRef.current;
    if (!ws) return;
    if (ws.isPlaying()) {
      ws.pause();
    } else {
      ws.play();
    }
  };

  const handleSend = () => {
    const rec = recordedRef.current;
    if (!rec) return;
    onComplete(rec);
  };

  return (
    <motion.div
      key="voice-recorder"
      initial={{ opacity: 0, y: 6 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.18 }}
      className={cn(
        "flex items-center gap-1.5 rounded-wx-lg border border-wx-border bg-wx-bg px-2 py-2",
      )}
    >
      <IconBtn
        Icon={XIcon}
        onClick={handleCancel}
        ariaLabel={t("cancelRecording")}
        intent="ghost"
      />

      {/* `min-w-0` on BOTH flex levels is load-bearing: a flex item's
          default `min-width: auto` won't let it shrink below its
          content's intrinsic width. wavesurfer's continuous-waveform
          canvas can be far wider than a narrow embedded preview — so
          without `min-w-0` the container refuses to shrink, grows to
          fit, wavesurfer's ResizeObserver re-renders even wider, and
          the bar oscillates forever. `overflow-hidden` on the
          waveform host clips any residual overscroll. */}
      <div className="flex h-9 min-w-0 flex-1 items-center gap-2 rounded-full bg-wx-bg-elevated px-3">
        {phase === "recording" && (
          <span
            aria-hidden="true"
            className="h-2 w-2 shrink-0 animate-pulse rounded-full bg-wx-danger"
          />
        )}
        <div
          ref={containerRef}
          aria-hidden="true"
          className={cn(
            "min-w-0 flex-1 overflow-hidden",
            // Click-to-seek only matters in preview; during recording
            // the canvas has nothing to seek to and we don't want
            // it competing with action buttons for taps.
            phase !== "preview" && "pointer-events-none",
          )}
        />
        <span className="shrink-0 font-mono text-xs tabular-nums text-wx-fg-muted">
          {formatDuration(elapsedSec)}
        </span>
      </div>

      {phase === "recording" && (
        <motion.button
          type="button"
          onClick={handleStop}
          aria-label={t("stopRecording")}
          whileHover={{ scale: 1.08 }}
          whileTap={{ scale: 0.9 }}
          transition={{ type: "spring", stiffness: 400, damping: 22 }}
          className={cn(
            "flex h-8 w-8 shrink-0 items-center justify-center rounded-full transition-colors",
            "text-wx-fg-muted hover:bg-wx-bg-elevated hover:text-wx-fg",
          )}
        >
          <Square size={14} />
        </motion.button>
      )}

      {phase === "preview" && (
        <>
          <IconBtn
            Icon={previewPlaying ? PauseIcon : PlayIcon}
            onClick={handlePreviewToggle}
            ariaLabel={previewPlaying ? t("pauseRecording") : t("playPreview")}
            intent="ghost"
          />
          <motion.button
            type="button"
            onClick={handleSend}
            aria-label={t("sendCta")}
            whileHover={{ scale: 1.08 }}
            whileTap={{ scale: 0.9 }}
            transition={{ type: "spring", stiffness: 400, damping: 22 }}
            className={cn(
              "flex h-8 w-8 shrink-0 items-center justify-center rounded-full transition-colors",
              "bg-wx-primary text-wx-primary-fg hover:bg-wx-primary-hover",
            )}
          >
            <Send size={14} />
          </motion.button>
        </>
      )}
    </motion.div>
  );
}

/**
 * Tight icon button for the recorder bar. Every glyph in here is a
 * `lucide-animated` icon, which wraps its SVG in a `<div>` that
 * exposes `startAnimation` / `stopAnimation` on its ref handle —
 * `useIconHover` propagates the button-level hover/focus to those
 * methods so the icon animates only when the visitor hovers the tap
 * target, not the SVG itself (the SVG sits behind the button's
 * hit area, so direct hover never works the way visitors expect).
 *
 * Type-wise, every lucide-animated icon's ref handle implements the
 * same `startAnimation?()` / `stopAnimation?()` shape — the union of
 * those handles is structurally compatible with `useIconHover`'s
 * default, so a single helper covers every icon we use.
 */
type LucideAnimatedHandle = {
  // Match `lucide-animated`'s per-icon `*IconHandle` types, which declare
  // these as non-optional. Marking them optional here makes the local
  // type unassignable from the real handle (TS can't widen `() => void`
  // to `(() => void) | undefined` at a covariant ref position), which
  // surfaces as the `Icon={XIcon}` build error.
  startAnimation: () => void;
  stopAnimation: () => void;
};

type LucideAnimatedIcon = ComponentType<{
  ref?: React.Ref<LucideAnimatedHandle>;
  size?: number;
}>;

function IconBtn({
  Icon,
  onClick,
  ariaLabel,
  intent,
  size = 16,
}: {
  Icon: LucideAnimatedIcon;
  onClick: () => void;
  ariaLabel: string;
  intent: "ghost" | "primary";
  size?: number;
}) {
  const hover = useIconHover<LucideAnimatedHandle>();
  return (
    <motion.button
      type="button"
      onClick={onClick}
      aria-label={ariaLabel}
      whileHover={{ scale: 1.08 }}
      whileTap={{ scale: 0.9 }}
      transition={{ type: "spring", stiffness: 400, damping: 22 }}
      {...hover.parentHandlers}
      className={cn(
        "flex h-8 w-8 shrink-0 items-center justify-center rounded-full transition-colors",
        intent === "primary"
          ? "bg-wx-primary text-wx-primary-fg hover:bg-wx-primary-hover"
          : "text-wx-fg-muted hover:bg-wx-bg-elevated hover:text-wx-fg",
      )}
    >
      <Icon ref={hover.iconRef} size={size} />
    </motion.button>
  );
}
