/**
 * Pure helpers for the voice recorder bar — duration formatting, MIME
 * selection, and base64 decoding. Kept out of the component so the
 * formatting + MIME logic can be unit-tested in isolation.
 */

/** Format a second count as `m:ss` (e.g. 75 → "1:15"). Clamps negatives. */
export function formatDuration(totalSec: number): string {
  const safe = Math.max(0, totalSec);
  const m = Math.floor(safe / 60);
  const s = safe % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

/**
 * Per-browser MIME pick. Chrome/Firefox prefer `audio/webm`; Safari
 * only supports `audio/mp4`. Returning `null` lets the MediaRecorder
 * pick its own default — the BE accepts both opus + aac via the
 * existing audio-mime allowlist.
 */
export function pickMime(): string | null {
  if (typeof MediaRecorder === "undefined") return null;
  const candidates = ["audio/webm;codecs=opus", "audio/webm", "audio/mp4", "audio/ogg"];
  for (const m of candidates) {
    if (MediaRecorder.isTypeSupported?.(m)) return m;
  }
  return null;
}

/** Decode a Blob to its raw base64 payload (strips the data-URL prefix). */
export async function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result;
      if (typeof result !== "string") {
        reject(new Error("FileReader returned non-string result"));
        return;
      }
      const comma = result.indexOf(",");
      resolve(comma >= 0 ? result.slice(comma + 1) : result);
    };
    reader.onerror = () => reject(reader.error ?? new Error("read failed"));
    reader.readAsDataURL(blob);
  });
}
